import java.util.Arrays;
import java.util.Comparator;

public class Main {
    static int maxActivities(int[][] activities) {
        Arrays.sort(activities, Comparator.comparingInt(a -> a[1])); // sort by END time

        int count = 1;
        int lastEnd = activities[0][1];

        for (int i = 1; i < activities.length; i++) {
            if (activities[i][0] >= lastEnd) {
                count++;
                lastEnd = activities[i][1];
            }
        }
        return count;
    }

    public static void main(String[] args) {
        int[][] activities = {{1, 3}, {2, 5}, {4, 6}, {6, 8}, {5, 9}};
        System.out.println(maxActivities(activities));
    }
}

public class Main {
    static int minCoinsGreedy(int[] coins, int amount) {
        int count = 0;
        for (int i = coins.length - 1; i >= 0; i--) {
            while (amount >= coins[i]) {
                amount -= coins[i];
                count++;
            }
        }
        return amount == 0 ? count : -1;
    }

    public static void main(String[] args) {
        int[] coins = {1, 5, 10, 25}; // sorted ascending -- standard US coins
        System.out.println(minCoinsGreedy(coins, 41));
    }
}

